import { Scissors, ChevronLeft, User, LogOut, Save, Database } from 'lucide-react';

export default function Header({ 
  title, 
  subtitle, 
  onBack, 
  user, 
  onLogout, 
  steps, 
  onSave, 
  saving, 
  saveMsg 
}) {
  return (
    // CORRECTION: On retire 'sticky' et on utilise un header standard avec une marge en bas (mb-6)
    <header className="w-full bg-[#0a0a0a] border-b border-white/5 shadow-lg shadow-black/20 mb-6 relative z-40">
      <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">

        {/* GAUCHE */}
        <div className="flex items-center gap-4 flex-1 min-w-0">
          {onBack && (
            <button 
              onClick={onBack}
              className="p-2 -ml-2 rounded-lg text-slate-400 hover:text-white hover:bg-white/5 transition-all"
            >
              <ChevronLeft className="w-6 h-6" />
            </button>
          )}

          <div className="flex items-center gap-3 min-w-0">
            <div className="w-9 h-9 bg-gradient-to-br from-orange-500 to-red-600 rounded-xl flex items-center justify-center shadow-lg flex-shrink-0">
              <Scissors className="w-5 h-5 text-white" />
            </div>
            <div className="min-w-0">
              <h1 className="text-lg font-black text-white leading-tight truncate">PanelCut <span className="text-orange-500">Pro</span></h1>
              {subtitle && <p className="text-[10px] text-slate-400 font-medium uppercase tracking-wider truncate">{subtitle}</p>}
            </div>
          </div>
        </div>

        {/* CENTRE: STEPPER */}
        {steps && steps.length > 0 && (
          <div className="hidden md:flex items-center gap-2 absolute left-1/2 -translate-x-1/2 bg-[#0f0f0f] px-4 py-1.5 rounded-full border border-white/5">
            {steps.map((step, idx) => (
              <div key={idx} className="flex items-center">
                <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase transition-all ${
                  step.active ? 'bg-orange-500 text-white shadow-lg' : 'bg-transparent text-slate-500'
                }`}>
                  <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] ${step.active ? 'bg-white/20' : 'bg-white/10 border'}`}>
                    {idx + 1}
                  </span>
                  <span className="hidden lg:inline">{step.label}</span>
                </div>
                {idx < steps.length - 1 && (
                  <div className={`w-6 h-0.5 mx-1 rounded-full ${step.active ? 'bg-orange-500/50' : 'bg-white/5'}`}></div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* DROITE */}
        <div className="flex items-center gap-3 flex-1 justify-end">
          {(saveMsg || saving) && (
            <div className={`hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold ${
              saveMsg?.includes('✓') ? 'bg-green-500/10 text-green-400' : 'bg-blue-500/10 text-blue-400'
            }`}>
              {saving ? '💾...' : saveMsg}
            </div>
          )}
          {onSave && !saving && (
            <button onClick={onSave} className="hidden sm:flex items-center gap-2 bg-white/10 hover:bg-orange-500 text-slate-300 hover:text-white px-4 py-2 rounded-lg text-xs font-bold transition-all border border-white/10">
              <Save className="w-4 h-4" /> <span>Sauvegarder</span>
            </button>
          )}
          {(onSave || user) && <div className="w-px h-6 bg-white/10 hidden sm:block"></div>}
          {user ? (
            <div className="flex items-center gap-2 bg-white/5 border border-white/5 rounded-full pl-1 pr-3 py-1">
              <div className="w-7 h-7 bg-gradient-to-tr from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-xs font-bold text-white">
                {user.email ? user.email[0].toUpperCase() : 'U'}
              </div>
              <span className="text-xs font-medium text-slate-300 max-w-[100px] truncate hidden sm:inline">
                {user.email?.split('@')[0]}
              </span>
              {onLogout && (
                <button onClick={onLogout} className="ml-1 p-1.5 text-slate-500 hover:text-red-400 rounded-full">
                  <LogOut className="w-3.5 h-3.5" />
                </button>
              )}
            </div>
          ) : (
             <div className="w-8 h-8 bg-white/5 rounded-full flex items-center justify-center border border-white/5">
               <User className="w-4 h-4 text-slate-500" />
             </div>
          )}
        </div>
      </div>
    </header>
  );
}
